import { createHash } from 'node:crypto';
import {
  BOUNDED_PATTERNS,
  CRITICAL_PATTERNS,
  type BoundedPattern,
  type CriticalPattern,
} from './patterns.js';

export interface BoundedHit {
  readonly pattern: BoundedPattern;
  readonly matches: string[];
}

export interface DetectionResult {
  readonly criticalHit: CriticalPattern | null;
  readonly boundedHits: ReadonlyArray<BoundedHit>;
  readonly anyHit: boolean;
}

/**
 * Run all patterns against `text`. Returns critical hit (first match) and
 * every bounded hit (so AUDIT mode logs full coverage even when critical
 * fires). Pure function — does not mutate or log.
 */
export function detect(text: string): DetectionResult {
  let criticalHit: CriticalPattern | null = null;
  for (const p of CRITICAL_PATTERNS) {
    if (p.re.test(text)) {
      criticalHit = p;
      break;
    }
  }

  const boundedHits: BoundedHit[] = [];
  for (const p of BOUNDED_PATTERNS) {
    p.re.lastIndex = 0;
    const all = text.match(p.re);
    if (all && all.length > 0) {
      boundedHits.push({ pattern: p, matches: all });
    }
  }

  return {
    criticalHit,
    boundedHits,
    anyHit: criticalHit != null || boundedHits.length > 0,
  };
}

/**
 * Apply BOUNDED replacements only. Critical pattern handling is a separate
 * concern (gate, not redact) — see hook entry point.
 */
export function applyRedactions(text: string, hits: readonly BoundedHit[]): string {
  let out = text;
  for (const { pattern } of hits) {
    pattern.re.lastIndex = 0;
    out = out.replace(pattern.re, `[REDACTED:${pattern.name}]`);
  }
  return out;
}

/**
 * SHA-256 of matched spans, truncated to 12 chars. Used in audit logs so
 * we can dedup repeat matches without storing the secret itself.
 */
export function hashSpans(spans: string[]): string {
  if (spans.length === 0) return '';
  const h = createHash('sha256');
  for (const s of spans) h.update(s);
  return h.digest('hex').slice(0, 12);
}

/**
 * Stringify tool_output for scanning. Read returns string; Bash returns
 * string; Grep can return array. Returns null if uncoercable.
 */
export function stringifyOutput(output: unknown): string | null {
  if (typeof output === 'string') return output;
  if (output == null) return null;
  if (Array.isArray(output)) {
    try {
      return output.map((x) => (typeof x === 'string' ? x : JSON.stringify(x))).join('\n');
    } catch {
      return null;
    }
  }
  try {
    return JSON.stringify(output);
  } catch {
    return null;
  }
}
